import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { map } from 'rxjs';
import { IngestionJob } from './models';

/** Raw `IngestionRun` row from the admin-only ingestion API. */
interface IngestionRun {
  id: string;
  startedAt: string;
  finishedAt: string | null;
  status: 'RUNNING' | 'SUCCESS' | 'FAILED';
  errorDetail: string | null;
  targetDate: string | null;
}

const STATUS_MAP: Record<IngestionRun['status'], IngestionJob['status']> = {
  RUNNING: 'running',
  SUCCESS: 'success',
  FAILED: 'failed',
};

/**
 * Ingestion job client (admin-only). Inspects job history and triggers the
 * daily refresh / one-time normals import. Maps the backend `IngestionRun`
 * rows onto the `IngestionJob` view model the jobs table renders.
 */
@Injectable({ providedIn: 'root' })
export class IngestionApiService {
  private readonly http = inject(HttpClient);

  /** Job history for the admin jobs table, newest first. */
  listJobs(limit = 50): Observable<IngestionJob[]> {
    return this.http
      .get<IngestionRun[]>('/api/admin/ingestion/runs', {
        params: { limit },
      })
      .pipe(map((runs) => runs.map((r) => this.toJob(r))));
  }

  /** Trigger a daily ingestion run now (optionally for a specific date). */
  trigger(date?: string): Observable<IngestionJob> {
    return this.http
      .post<IngestionRun>('/api/admin/ingestion/run', date ? { date } : {})
      .pipe(map((r) => this.toJob(r)));
  }

  /** Trigger the one-time Climate Normals baseline import. */
  importNormals(): Observable<{ stationsProcessed: number; normalsUpserted: number }> {
    return this.http.post<{ stationsProcessed: number; normalsUpserted: number }>(
      '/api/admin/ingestion/normals',
      {},
    );
  }

  private toJob(r: IngestionRun): IngestionJob {
    const started = Date.parse(r.startedAt);
    const finished = r.finishedAt ? Date.parse(r.finishedAt) : null;
    return {
      id: r.id,
      targetDate: r.targetDate ? r.targetDate.slice(0, 10) : '—',
      source: 'GHCN-Daily',
      status: STATUS_MAP[r.status] ?? 'running',
      startedAt: r.startedAt,
      finishedAt: r.finishedAt,
      durationMs:
        finished !== null && Number.isFinite(started)
          ? Math.max(0, finished - started)
          : null,
      stationsIngested: 0,
      attempts: 1,
      message: r.errorDetail,
    };
  }
}
